// ─── Core Grid ────────────────────────────────────────────────────────────────
export const LO_SHU_LAYOUT = [[4,9,2],[3,5,7],[8,1,6]];

export interface LoShuGrid {
  cells: { [n: number]: number[] };
  counts: { [n: number]: number };
  present: number[];
  missing: number[];
  repeated: number[];
}

export function reduce(n: number): number {
  while (n > 9) n = String(n).split("").reduce((a,d)=>a+Number(d),0);
  return n;
}

export function extractDigits(dob: string): number[] {
  return dob.replace(/\D/g,"").split("").map(Number).filter(d=>d!==0);
}

export function buildGrid(digits: number[]): LoShuGrid {
  const cells: {[n:number]:number[]} = {};
  const counts: {[n:number]:number} = {};
  for (let i=1;i<=9;i++){cells[i]=[];counts[i]=0;}
  for (const d of digits) if (d>=1&&d<=9){cells[d].push(d);counts[d]++;}
  return {
    cells, counts,
    present: [1,2,3,4,5,6,7,8,9].filter(k=>counts[k]>0),
    missing: [1,2,3,4,5,6,7,8,9].filter(k=>counts[k]===0),
    repeated: [1,2,3,4,5,6,7,8,9].filter(k=>counts[k]>1),
  };
}

export function calcMoolank(dob:string):number { const p=dob.split("-"); return p.length<3?0:reduce(parseInt(p[2])); }
export function calcBhagyank(dob:string):number { return reduce(dob.replace(/\D/g,"").split("").reduce((a,d)=>a+Number(d),0)); }
export function calcMonthNum(dob:string):number { const p=dob.split("-"); return p.length<2?0:reduce(parseInt(p[1])); }
export function calcYearNum(dob:string):number { const p=dob.split("-"); return p.length<1?0:reduce(parseInt(p[0])); }
export function calcPersonalYear(dob:string, yr:number):number { const p=dob.split("-"); return p.length<3?0:reduce(parseInt(p[1])+parseInt(p[2])+yr); }
export function planePercent(counts:{[k:number]:number},nums:number[]):number {
  return Math.round(nums.filter(n=>counts[n]>0).length/nums.length*100);
}
export function planePresentStr(counts:{[k:number]:number},nums:number[]):string {
  return nums.map(n=>counts[n]>0?Array(counts[n]).fill(n).join(""):"").join(",");
}
export function calcKua(dob:string, gender:"male"|"female"):number {
  const p=dob.split("-"); if(!p[0])return 0;
  const yr=parseInt(p[0]); const sum=reduce(yr%100);
  if(gender==="male"){const k=yr<2000?10-sum:9-sum; return k===5?2:reduce(k<1?k+9:k);}
  else{const k=yr<2000?5+sum:6+sum; return k===5?8:reduce(k);}
}
export function westSign(dob:string):string {
  const p=dob.split("-"); if(p.length<3)return ""; const m=parseInt(p[1]),d=parseInt(p[2]);
  if((m===12&&d>=22)||(m===1&&d<=19))return "Capricorn";
  if((m===1&&d>=20)||(m===2&&d<=18))return "Aquarius";
  if((m===2&&d>=19)||(m===3&&d<=20))return "Pisces";
  if((m===3&&d>=21)||(m===4&&d<=19))return "Aries";
  if((m===4&&d>=20)||(m===5&&d<=20))return "Taurus";
  if((m===5&&d>=21)||(m===6&&d<=20))return "Gemini";
  if((m===6&&d>=21)||(m===7&&d<=22))return "Cancer";
  if((m===7&&d>=23)||(m===8&&d<=22))return "Leo";
  if((m===8&&d>=23)||(m===9&&d<=22))return "Virgo";
  if((m===9&&d>=23)||(m===10&&d<=22))return "Libra";
  if((m===10&&d>=23)||(m===11&&d<=21))return "Scorpio";
  return "Sagittarius";
}
export function eastSign(dob:string):string {
  const signs=["Aries","Taurus","Gemini","Cancer","Leo","Virgo","Libra","Scorpio","Sagittarius","Capricorn","Aquarius","Pisces"];
  const p=dob.split("-"); if(p.length<3)return "";
  let m=parseInt(p[1]),d=parseInt(p[2]); d-=23; if(d<=0){m-=1;d+=30;} if(m<=0)m+=12;
  return signs[((m-1)+12)%12];
}

// ─── Chaldean Name Number ─────────────────────────────────────────────────────
const CHALDEAN:{[ch:string]:number} = {
  A:1,Q:1,Y:1,I:1,J:1, B:2,R:2,K:2, G:3,C:3,L:3,S:3,
  D:4,M:4,T:4, E:5,H:5,N:5,X:5, U:6,V:6,W:6, O:7,Z:7, F:8,P:8
};
export function chaldeanValue(name:string):number {
  return name.toUpperCase().replace(/[^A-Z]/g,"").split("").reduce((a,c)=>a+(CHALDEAN[c]||0),0);
}
export function nameNumber(name:string):{compound:number;single:number;count:number} {
  const val=chaldeanValue(name);
  return {compound:val, single:reduce(val), count:name.replace(/[^a-zA-Z]/g,"").length};
}

