function fmtDate(d:Date):string { return `${String(d.getDate()).padStart(2,"0")}-${String(d.getMonth()+1).padStart(2,"0")}-${d.getFullYear()}`; }

export function calcMahaDasha(dob:string):DashaEntry[] {
  const parts=dob.split("-"); if(parts.length<3)return [];
  const result:DashaEntry[]=[];
  let current=new Date(dob);
  for(let cycle=0;cycle<3;cycle++){
    for(const md of DASHA_SEQ){
      const start=new Date(current);
      const end=new Date(current); end.setFullYear(end.getFullYear()+md.dur);
      result.push({planet:md.planet,num:md.num,start:fmtDate(start),end:fmtDate(end),dur:md.dur,desc:md.desc});
      current=new Date(end);
      if(current.getFullYear()>new Date().getFullYear()+60)break;
    }
    if(current.getFullYear()>new Date().getFullYear()+60)break;
  }
  return result;
}

