export type Gender="male"|"female";
export interface FullReport {
  name:string; dob:string; gender:Gender;
  digits:number[]; grid:LoShuGrid;
  moolank:number; bhagyank:number; monthNum:number; yearNum:number;
  kuaMale:number; kuaFemale:number;
  westernSign:string; easternSign:string;
  mahaDasha:DashaEntry[];
  lucky:typeof LUCKY_DATA[1];
  personalYears:{year:number;num:number;predictions:string[]}[];
  nameData:{firstName:string;lastName:string;fullCompound:number;fullSingle:number;firstCompound:number;firstSingle:number;totalLetters:number;firstLetters:number};
}

export function generateReport(name:string,dob:string,gender:Gender):FullReport {
  const digits=extractDigits(dob);
  const grid=buildGrid(digits);
  const moolank=calcMoolank(dob);
  const bhagyank=calcBhagyank(dob);
  const parts=name.trim().split(/\s+/);
  const firstName=parts[0]||"";
  const lastName=parts.slice(1).join(" ");
  const fullNd=nameNumber(name);
  const firstNd=nameNumber(firstName);
  const currentYear=new Date().getFullYear();
  return {
    name, dob, gender, digits, grid, moolank, bhagyank,
    monthNum:calcMonthNum(dob), yearNum:calcYearNum(dob),
    kuaMale:calcKua(dob,"male"), kuaFemale:calcKua(dob,"female"),
    westernSign:westSign(dob), easternSign:eastSign(dob),
    mahaDasha:calcMahaDasha(dob),
    lucky:LUCKY_DATA[moolank]||LUCKY_DATA[1],
    personalYears:[0,1,2,3,4,5].map(o=>{ const yr=currentYear+o; const num=calcPersonalYear(dob,yr); return{year:yr,num,predictions:PY_DATA[num]||[]}; }),
    nameData:{firstName,lastName,fullCompound:fullNd.compound,fullSingle:fullNd.single,totalLetters:fullNd.count,firstCompound:firstNd.compound,firstSingle:firstNd.single,firstLetters:firstNd.count},
  };
}
